// rulesForCategory filters rules by category.
func rulesForCategory(rules []rule.Rule, category string) []rule.Rule {
	var result []rule.Rule
	for _, r := range rules {
		if string(r.Category) == category {
			result = append(result, r)
		}
	}
	return result
}

// imageSubtypePrefixes is the canonical ordered list of image sub-type prefixes
// used for grouping image rules and validating rule IDs. Shared between
